  client_cidr_block      = "10.0.0.0/22"

  authentication_options {
    type                       = "certificate-authentication"
    root_certificate_chain_arn = "arn:aws:acm:<REGION>:<ACCOUNT_ID>:certificate/<example_resource_id>"
  }

  connection_log_options {                # CRITICAL: enables client connection logging
    enabled             = true            # CRITICAL: turns on logging
    cloudwatch_log_group = "<example_resource_name>"  # CRITICAL: destination log group
  }
}

